// src/components/InternshipCard.jsx
import React from "react";
import { FaBriefcase, FaMapMarkerAlt, FaBuilding } from "react-icons/fa";

export default function InternshipCard({ internship, currentUser, onApply, isApplied, onEdit, onDelete, onView }) {
  return (
    <div className="bg-white rounded-xl shadow-md p-6 transition hover:shadow-lg border border-gray-200">
      <div className="flex items-center justify-between mb-2">
        <h3 className="text-xl font-bold text-green-700">{internship.title}</h3>
        {onView && (
          <button
            onClick={() => onView(internship)}
            className="text-sm text-blue-600 hover:underline"
          >
            View Details
          </button>
        )}
      </div>

      <p className="flex items-center text-sm text-gray-600 mb-1">
        <FaBuilding className="mr-2 text-gray-500" /> {internship.company}
      </p>
      <p className="flex items-center text-sm text-gray-600 mb-1">
        <FaBriefcase className="mr-2 text-gray-500" /> {internship.category} | {internship.mode}
      </p>
      <p className="flex items-center text-sm text-gray-600 mb-2">
        <FaMapMarkerAlt className="mr-2 text-gray-500" /> {internship.location}
      </p>

      <p className="text-gray-700 text-sm">{internship.description?.slice(0, 120)}...</p>

      <div className="mt-4 flex flex-wrap gap-2">
        {currentUser?.role === "student" && (
          <button
            onClick={() => onApply(internship._id)}
            disabled={isApplied}
            className={`px-4 py-2 rounded text-sm font-medium ${
              isApplied
                ? "bg-gray-400 text-white cursor-not-allowed"
                : "bg-green-600 text-white hover:bg-green-700"
            }`}
          >
            {isApplied ? "Applied" : "Apply Now"}
          </button>
        )}

        {(currentUser?.role === "admin" || currentUser?.role === "hr") && (
          <>
            <button
              onClick={() => onEdit(internship)}
              className="px-4 py-2 rounded bg-yellow-500 text-white text-sm hover:bg-yellow-600"
            >
              Edit
            </button>
            <button
              onClick={() => onDelete(internship._id)}
              className="px-4 py-2 rounded bg-red-600 text-white text-sm hover:bg-red-700"
            >
              Delete
            </button>
          </>
        )}
      </div>
    </div>
  );
}
